import React, { useEffect, useState } from "react";
import EventList from "../components/EventList";
import api from "../api";
import Fuse from "fuse.js"; // for fuzzy search

const BrowseEvents = () => {
  const [events, setEvents] = useState([]);
  const [filteredEvents, setFilteredEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [filters, setFilters] = useState({
    type: "all", // "normal", "merchandise"
    eligibility: "all",
    startDate: "",
    endDate: "",
  });
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchEvents = async () => {
      try {
        setLoading(true);
        const token = localStorage.getItem("token");
        const res = await api.get("/events", {
          headers: { Authorization: `Bearer ${token}` },
        });
        setEvents(res.data);
      } catch (err) {
        console.error(err);
        setError("Failed to fetch events");
      } finally {
        setLoading(false);
      }
    };

    fetchEvents();
  }, []);

  // Filtering + search
  useEffect(() => {
    let temp = [...events];

    // Filter by type
    if (filters.type !== "all") {
      temp = temp.filter((e) => e.type === filters.type);
    }

    // Filter by eligibility
    if (filters.eligibility !== "all") {
      temp = temp.filter((e) => e.eligibility === filters.eligibility);
    }

    // Filter by date range
    if (filters.startDate) {
      temp = temp.filter((e) => new Date(e.startDate) >= new Date(filters.startDate));
    }
    if (filters.endDate) {
      temp = temp.filter((e) => new Date(e.endDate) <= new Date(filters.endDate));
    }

    // Fuzzy search using Fuse.js
    if (search) {
      const fuse = new Fuse(temp, {
        keys: ["name", "organiser.firstName", "organiser.lastName"],
        threshold: 0.3, // 0.0 = exact, 1.0 = fuzzy
      });
      temp = fuse.search(search).map((result) => result.item);
    }

    setFilteredEvents(temp);
  }, [events, search, filters]);

  // Top 5 trending events (created within last 24h and most participants)
  const trendingEvents = events
    .filter((e) => new Date(e.createdAt) > new Date(Date.now() - 24 * 60 * 60 * 1000))
    .sort((a, b) => b.participants.length - a.participants.length)
    .slice(0, 5);

  const handleRegister = async (eventId) => {
    try {
      const token = localStorage.getItem("token");
      await api.post(`/events/register/${eventId}`, {}, {
        headers: { Authorization: `Bearer ${token}` },
      });
      alert("Registered successfully");
    } catch (err) {
      alert(err.response?.data?.message || "Failed to register");
    }
  };

  return (
    <div className="container mx-auto p-4">
      <h1 className="text-2xl font-bold mb-4">Browse Events</h1>

      {/* Search */}
      <input
        type="text"
        placeholder="Search events or organisers..."
        className="border p-2 mb-4 w-full"
        value={search}
        onChange={(e) => setSearch(e.target.value)}
      />

      {/* Filters */}
      <div className="flex gap-4 mb-4 flex-wrap">
        <select
          value={filters.type}
          onChange={(e) => setFilters({ ...filters, type: e.target.value })}
          className="border p-2"
        >
          <option value="all">All Types</option>
          <option value="normal">Normal</option>
          <option value="merchandise">Merchandise</option>
        </select>

        <select
          value={filters.eligibility}
          onChange={(e) => setFilters({ ...filters, eligibility: e.target.value })}
          className="border p-2"
        >
          <option value="all">All Eligibility</option>
          <option value="All Participants">All Participants</option>
          <option value="VIP Only">VIP Only</option>
          {/* Add more eligibility options if needed */}
        </select>

        <input
          type="date"
          value={filters.startDate}
          onChange={(e) => setFilters({ ...filters, startDate: e.target.value })}
          className="border p-2"
        />

        <input
          type="date"
          value={filters.endDate}
          onChange={(e) => setFilters({ ...filters, endDate: e.target.value })}
          className="border p-2"
        />
      </div>

      {/* Loading & error */}
      {loading && <p>Loading events...</p>}
      {error && <p className="text-red-500">{error}</p>}

      {/* Trending */}
      {trendingEvents.length > 0 && (
        <div className="mb-6">
          <h2 className="text-xl font-semibold mb-2">Trending (24h)</h2>
          <EventList events={trendingEvents} onRegister={handleRegister} />
        </div>
      )}

      {/* Filtered events */}
      <div>
        <h2 className="text-xl font-semibold mb-2">All Events</h2>
        <EventList events={filteredEvents} onRegister={handleRegister} />
      </div>
    </div>
  );
};

export default BrowseEvents;
